+import type { AnyColumn } from '~/column.ts';
+import { is } from '~/entity.ts';
+import { Column, type SQL, sql, type SQLWrapper } from '../sql.ts';
+
+export type WindowFrameBoundary =
+	| { type: 'unbounded preceding' | 'current row' | 'unbounded following' }
+	| { type: 'preceding' | 'following'; value: number };
+
+export const unboundedPreceding: WindowFrameBoundary = { type: 'unbounded preceding' };
+export const currentRow: WindowFrameBoundary = { type: 'current row' };
+export const unboundedFollowing: WindowFrameBoundary = { type: 'unbounded following' };
+
+function offsetBoundary(type: 'preceding' | 'following', value: number): WindowFrameBoundary {
+	if (!Number.isInteger(value) || value < 0) throw new Error(`${type}() requires a non-negative integer; received ${value}`);
+	return { type, value };
+}
+
+export function preceding(value: number): WindowFrameBoundary { return offsetBoundary('preceding', value); }
+export function following(value: number): WindowFrameBoundary { return offsetBoundary('following', value); }
+
+export interface WindowFrame { type: 'rows' | 'range'; from: WindowFrameBoundary; to: WindowFrameBoundary }
+
+const boundaryOrder = (boundary: WindowFrameBoundary): number => {
+	if (boundary.type === 'unbounded preceding') return Number.NEGATIVE_INFINITY;
+	if (boundary.type === 'unbounded following') return Number.POSITIVE_INFINITY;
+	if (boundary.type === 'current row') return 0;
+	return boundary.type === 'preceding' ? -boundary.value : boundary.value;
+};
+
+function frame(type: WindowFrame['type'], spec: { from: WindowFrameBoundary; to: WindowFrameBoundary }): WindowFrame {
+	if (boundaryOrder(spec.from) > boundaryOrder(spec.to)) throw new Error('Window frame "from" boundary must not be after "to"');
+	return { type, ...spec };
+}
+
+export function rows(spec: { from: WindowFrameBoundary; to: WindowFrameBoundary }): WindowFrame { return frame('rows', spec); }
+export function range(spec: { from: WindowFrameBoundary; to: WindowFrameBoundary }): WindowFrame { return frame('range', spec); }
+
+export interface WindowSpec {
+	partitionBy?: SQLWrapper | SQLWrapper[];
+	orderBy?: SQLWrapper | SQLWrapper[];
+	frame?: WindowFrame;
+}
+
+function boundarySql(boundary: WindowFrameBoundary): SQL {
+	return 'value' in boundary ? sql.raw(`${boundary.value} ${boundary.type}`) : sql.raw(boundary.type);
+}
+
+export function buildWindowSpec(spec: WindowSpec): SQL {
+	const partitionBy = spec.partitionBy && (Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy]);
+	const orderBy = spec.orderBy && (Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy]);
+	const frameSql = spec.frame && sql` ${sql.raw(spec.frame.type)} between ${boundarySql(spec.frame.from)} and ${boundarySql(spec.frame.to)}`;
+	return sql`${partitionBy?.length ? sql`partition by ${sql.join(partitionBy, sql`, `)} ` : undefined}${orderBy?.length ? sql`order by ${sql.join(orderBy, sql`, `)}` : undefined}${frameSql}`;
+}
+
+export class WindowFunction<T> implements SQLWrapper {
+	constructor(private readonly expression: SQL<T>) {}
+	over(spec?: WindowSpec | string): SQL<T> {
+		return typeof spec === 'string'
+			? sql`${this.expression} over ${sql.identifier(spec)}`
+			: sql`${this.expression} over (${buildWindowSpec(spec ?? {})})`;
+	}
+	getSQL(): SQL<T> { return this.expression; }
+}
+
+function windowFunction<T>(name: string, args: SQLWrapper[] = []): WindowFunction<T> {
+	return new WindowFunction(sql`${sql.raw(name)}(${sql.join(args, sql`, `)})`);
+}
+
+function position(name: string, value: number): WindowFunction<number> {
+	if (!Number.isInteger(value) || value <= 0) throw new Error(`${name}() requires a positive integer; received ${value}`);
+	return windowFunction(name, [sql.raw(String(value))]);
+}
+
+export const rowNumber = (): WindowFunction<number> => windowFunction('row_number');
+export const rank = (): WindowFunction<number> => windowFunction('rank');
+export const denseRank = (): WindowFunction<number> => windowFunction('dense_rank');
+export const ntile = (buckets: number): WindowFunction<number> => position('ntile', buckets);
+export const percentRank = (): WindowFunction<number> => windowFunction('percent_rank');
+export const cumeDist = (): WindowFunction<number> => windowFunction('cume_dist');
+
+type Value<T extends SQLWrapper> = T extends AnyColumn ? T['_']['data'] : T extends SQL<infer TValue> ? TValue : unknown;
+type NullableValue<T extends SQLWrapper> = Value<T> | null;
+
+export function lag<T extends SQLWrapper>(value: T, offset?: number): WindowFunction<NullableValue<T>>;
+export function lag<T extends SQLWrapper, TDefault extends SQLWrapper>(value: T, offset: number | undefined, defaultValue: TDefault): WindowFunction<Exclude<Value<T>, null> | Value<TDefault>>;
+export function lag(value: SQLWrapper, offset?: number, defaultValue?: SQLWrapper): WindowFunction<unknown> { return windowFunction('lag', [value, ...(offset === undefined ? [] : [sql.raw(String(offset))]), ...(defaultValue === undefined ? [] : [defaultValue])]); }
+export function lead<T extends SQLWrapper>(value: T, offset?: number): WindowFunction<NullableValue<T>>;
+export function lead<T extends SQLWrapper, TDefault extends SQLWrapper>(value: T, offset: number | undefined, defaultValue: TDefault): WindowFunction<Exclude<Value<T>, null> | Value<TDefault>>;
+export function lead(value: SQLWrapper, offset?: number, defaultValue?: SQLWrapper): WindowFunction<unknown> { return windowFunction('lead', [value, ...(offset === undefined ? [] : [sql.raw(String(offset))]), ...(defaultValue === undefined ? [] : [defaultValue])]); }
+export const firstValue = <T extends SQLWrapper>(value: T): WindowFunction<NullableValue<T>> => windowFunction('first_value', [value]);
+export const lastValue = <T extends SQLWrapper>(value: T): WindowFunction<NullableValue<T>> => windowFunction('last_value', [value]);
+export const nthValue = <T extends SQLWrapper>(value: T, n: number): WindowFunction<NullableValue<T>> => position('nthValue', n) as unknown as WindowFunction<NullableValue<T>> && windowFunction('nth_value', [value, sql.raw(String(n))]);
+
+export const windowSum = (value: SQLWrapper): WindowFunction<string | null> => windowFunction('sum', [value]);
+export const windowAvg = (value: SQLWrapper): WindowFunction<string | null> => windowFunction('avg', [value]);
+export const windowMin = <T extends SQLWrapper>(value: T): WindowFunction<NullableValue<T>> => new WindowFunction(sql`min(${value})`.mapWith(is(value, Column) ? value : String) as SQL<NullableValue<T>>);
+export const windowMax = <T extends SQLWrapper>(value: T): WindowFunction<NullableValue<T>> => new WindowFunction(sql`max(${value})`.mapWith(is(value, Column) ? value : String) as SQL<NullableValue<T>>);
+export const windowCount = (value?: SQLWrapper): WindowFunction<number> => new WindowFunction(sql`count(${value ?? sql.raw('*')})`.mapWith(Number));
